""");

        sb.AppendLine("""
<div style="margin-bottom:16px;">
    <input id="search"
           type="text"
           onkeyup="searchTable()"
           placeholder="Search type, namespace, file..."
           style="width:100%; padding:12px; border-radius:10px; border:1px solid rgba(255,255,255,0.14); background:rgba(255,255,255,0.03); color:#fff;" />
